import { ApiClient } from "./client";
import type { ApiNamespace } from "./types";

// Cache for storing created API clients
const clientCache = new Map<string, ApiClient>();

// Generate a cache key for the given parameters
const getCacheKey = (performRedirect: boolean, namespace: string): string => {
  return `${namespace}-${performRedirect}`;
};

export const getApiClient = (
  performRedirect = true,
  namespace: ApiNamespace = "org",
): ApiClient => {
  const cacheKey = getCacheKey(performRedirect, namespace);

  // Check if we already have a client for this configuration
  const cachedClient = clientCache.get(cacheKey);
  if (cachedClient) {
    return cachedClient;
  }

  // Create a new client for this configuration
  const newClient = new ApiClient({
    namespace,
    performRedirect,
  });

  // Store it in the cache for future use
  clientCache.set(cacheKey, newClient);

  return newClient;
};

